local LxBaseState = require("LApp.component.fsm.LxBaseState")
---@class LCityPeopleNoneState:LxBaseState 小人状态--什么都不做
local LCityPeopleNoneState = classX("LCityPeopleNoneState", LxBaseState)

function LCityPeopleNoneState:ctor()
    self._stateType = CityPeopleFsmState.None;
    self.timeTick = 0;
end
function LCityPeopleNoneState:Initialize()
    LxBaseState.Initialize(self)
    ---@type LCityPeopleFsm
    self._fsm = self:GetMachine();
    ---@type LCityPeopleUnit
    self._unit = self._fsm:GetVar("unit");
    self._beginEat = false
    self._eatTime = 0
end
function LCityPeopleNoneState:Execute(deltaTime)
    --self.timeTick = self.timeTick+deltaTime;
    --if(self.timeTick >= 1)then
    --    self.timeTick = 1
    --end
    --self._unit:SetSpineAlpha(1-self.timeTick);
    if(self._beginEat)then
         self._eatTime = self._eatTime + deltaTime
        if(self._eatTime >= 1.5)then
            self._beginEat = false
            self._eatTime = 0
            self._unit:DoPatrol(false)
            self._unit:SetEatEnd(true)
            CtrlCenter.City:ResetEatNode(self._unit._eatNode)
            CtrlCenter.City:ContinueEat()
        end
    end
end

function LCityPeopleNoneState:Enter()
    self._beginEat = false
    self._eatTime = 0
    self.timeTick = 0;
    self._unit:PlayAni("idle")
    self._unit.peopleMgr:HidePeopleTextHUD(self._unit._peopleRefId)

    local peopleObj = ModuleCenter.People:GetPeopleObj(self._unit._peopleRefId)
    local buildRefId = peopleObj.building
    local buildingUnit = CtrlCenter.City:GetBuilding(buildRefId)

    if(buildingUnit and buildingUnit._inView)then
        self._unit:SetSpineAlpha(1);
    else
        self._unit:SetSpineAlpha(0);
    end
    if(self._unit:GetEatEnd())then
        --吃完饭了，在巡逻或睡觉
        return
    end
    local timeState = CtrlCenter.City:GetCurTimeState()

    if(timeState == 1)then
        --睡觉
        self._unit:SetDir(false)
        self._unit:PlayAni("sleep")
    elseif timeState == 2 then
        --工作
        self._unit:SetDir(false)
        self._unit:PlayAni("work")
    elseif timeState == 3 then
        --吃饭
        self._unit:PlayAni("eat",true, function()

        end)
        self._beginEat = true
    end
end
function LCityPeopleNoneState:Exit()
    self.timeTick = 0;
    self._beginEat = false
    self._eatTime = 0
end
function LCityPeopleNoneState:Dispose()
    self._unit = nil
    self._fsm = nil
    LxBaseState.Dispose(self)
end
return LCityPeopleNoneState